import{_ as t,o as n,c as a,a3 as i}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"12. Independent Dispute Resolution Panel","description":"","frontmatter":{"title":"12. Independent Dispute Resolution Panel","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["disputes","staffing","workload","classifications"]},"headers":[],"relativePath":"ebas/mspp/disputes/12-independent-dispute-resolution-panel.md","filePath":"ebas/mspp/disputes/12-independent-dispute-resolution-panel.md"}'),o={name:"ebas/mspp/disputes/12-independent-dispute-resolution-panel.md"};function s(r,e,p,l,h,d){return n(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="_12-independent-dispute-resolution-panel" tabindex="-1">12. Independent Dispute Resolution Panel <a class="header-anchor" href="#_12-independent-dispute-resolution-panel" aria-label="Permalink to &quot;12. Independent Dispute Resolution Panel&quot;">​</a></h1><p><strong>12.1</strong> Application The Independent Dispute Resolution Panel (Panel) is empowered to hear and determine dispute applications regarding the following matters:</p><p><strong>a.</strong> A dispute under this Agreement in relation to the classification of an Employee;</p><p><strong>b.</strong> Workload and/or staffing disputes that arise under the provisions of this Agreement; and</p><p><strong>c.</strong> Underpayment claims, where the Employer agrees to have a dispute about an alleged underpayment determined by the Panel.</p><p><strong>12.2</strong> Composition and principles of the Panel</p><p><strong>a.</strong> The Panel will comprise three persons being:</p><p><strong>(i)</strong> A nominee of the HSU (on behalf of Employees);</p><p><strong>(ii)</strong> A nominee of the VHIA (on behalf of Employers); and</p><p><strong>(iii)</strong> an independent chairperson (Chair) agreed by HSU and the VHIA or, in the absence of agreement, as nominated by the Minister for Health. Note: A nominee of the HSU or VHIA may change at any stage depending on the nature of the matter being determined by the Panel.</p><p><strong>b.</strong> The Panel Chair shall act as an independent third party in deliberations of the Panel.</p><p><strong>c.</strong> A nominee on the Panel must recuse themselves from being involved in a matter if they are directly and/or personally affected by the outcome.</p><p><strong>d.</strong> The Panel will commence to determine an application made under this clause within 21 days of receiving the application and conclude its deliberations as expeditiously as possible.</p><p><strong>e.</strong> The Panel shall act independently of the Department of Health, HSU and the VHIA.</p><p><strong>f.</strong> The parties to an application to the Panel bear their own costs (save for the Chair).</p><p><strong>g.</strong> The Panel shall be responsible for determining its own procedure, provided that it applies the rules of natural justice and procedural fairness and be consistent with the requirements of <a href="/eba/ebas/mspp/disputes/11-disputes-settling-procedures.html">clause 11</a> Disputes Settling Procedure.</p><p><strong>h.</strong> The Panel shall apply an inquisitorial procedure, rather than an adversarial one.</p><p><strong>i.</strong> The Panel may decide to hear a matter in the workplace. In such cases the employer shall provide a suitable meeting room and other relevant facilities for any date requested by the Panel. The employer will allow the Panel to inspect any work site if the Panel believes this will assist it in determining a matter, subject to any health, safety and privacy considerations. A party to a dispute may request that the Panel hear a matter in a workplace. The Panel will consider such a request and determine for itself the best location for hearing a matter.</p><p><strong>j.</strong> In the exercise of its functions, the Panel shall do such things as are necessary to ensure that:</p><p><strong>(i)</strong> matters are dealt with expeditiously; and</p><p><strong>(ii)</strong> where possible it does not deal with unnecessarily complex legal arguments in hearing/determining a matter;</p><p><strong>k.</strong> Lawyers and paid agents, who are not direct employees of the HSU, VHIA, Department of Health or an employer will not be given permission to appear before the Panel, except where the Panel determines it is appropriate having regard to the principles of this clause including natural justice under 12.2g.</p><p><strong>l.</strong> A party to a dispute that is being dealt with under this clause shall not make an application to the FWC for it to deal with the same dispute, other than an application made under clause 12.5l. Nothing prevents an application to the FWC where the Panel ceases to deal with a dispute without having made a determination.</p><p><strong>12.3</strong> Functions of the Panel Chair</p><p><strong>a.</strong> The Chair shall perform the following functions:</p><p><strong>(i)</strong> Notify all parties to the matter of the hearing dates;</p><p><strong>(ii)</strong> Chair proceedings of the Panel;</p><p><strong>(iii)</strong> Conciliate matters, by chairing conferences between the employer(s) and/or their representative/s, and the HSU;</p><p><strong>(iv)</strong> Anything else necessary to give effect to the provisions of this clause.</p><p><strong>12.4</strong> Application to Panel to deal with a dispute</p><p><strong>a.</strong> Either an Employer or an Employee (or their representatives) may make an application to the Panel regarding a dispute about matters listed at 12.1, only where the Parties have attempted to resolve the dispute at the workplace as described at <a href="/eba/ebas/mspp/disputes/11-disputes-settling-procedures.html">clause 11.4</a> of the enterprise agreement.</p><p><strong>b.</strong> If the provisions of <a href="/eba/ebas/mspp/disputes/11-disputes-settling-procedures.html">clause 11.4</a> (excluding 11.4c) (Discussion of dispute at workplace) or obligations set out at 11.2 of the Agreement have not been complied with prior to application, the Chair will refer the parties back to the workplace to attempt resolution through discussion at the workplace level in the first instance.</p><p><strong>c.</strong> Application by an Employee</p><p><strong>(i)</strong> The Chair shall notify the HSU, VHIA and the Employer of an application made by an employee directly to the Panel.</p><p><strong>(ii)</strong> Before referral to the Panel for determination, the Chair in the first instance shall review the employee’s application to determine that the nature of the dispute is within the scope of this clause and therefore able to be determined by the Panel.</p><p><strong>(iii)</strong> The Chair will notify the Employee, HSU, VHIA and the Employer of their findings with respect to scope.</p><p><strong>(iv)</strong> If the Chair finds the employee’s application is not within the scope of this clause the Chair will notify the Employee and that their application is not able to be heard by the Panel.</p><p><strong>(v)</strong> If the Chair finds the Employee’s application is within the scope of this clause the Chair will notify the Employee that it will be dealt with under this clause.</p><p><strong>12.5</strong> Role, procedures and determinations of the Panel</p><p><strong>a.</strong> In dealing with an application, the Panel will:</p><p><strong>(i)</strong> utilise available relevant material.</p><p><strong>(ii)</strong> apply the provisions of the Agreement;</p><p><strong>(iii)</strong> in the case of submissions under clause f below consider any materials submitted by or on behalf of the Department of Health.</p><p><strong>b.</strong> Subject to the provisions of this clause, proceedings of the Panel shall be conducted as informally as possible and undertaken with all possible expediency.</p><p><strong>c.</strong> The Panel may inform itself in any manner it sees fit including, in the case of a classification application, by seeking the views of an expert advisor (who is not an employee of the health service subject of the application) agreed by the Panel to provide clinical expertise in an area of clinical practice relevant to the classification matter under consideration.</p><p><strong>d.</strong> The Panel is not bound by the rules or practices as to evidence and may inform itself on any matter it thinks fit. In any event, an Employee providing evidence to the Panel will not be subjected to any form of cross examination by any person without limiting the questions the Panel may ask.</p><p><strong>e.</strong> The Employer or VHIA and the Employee/s and/or HSU can advocate to the Panel.</p><p><strong>f.</strong> At the Panel’s discretion, the parties to a matter will present submissions verbally and/or in writing.</p><p><strong>g.</strong> The parties to a dispute shall have full, unrestricted access to relevant information, except where the Panel determines that access to material is inappropriate for legal or confidentiality reasons.</p><p><strong>h.</strong> An Employee, including a HSU representative (for example, a HSU delegate or HSR), who is involved in a matter being heard by the Panel shall be allowed time off from their normal duties and paid their normal wages for time attending.</p><p><strong>i.</strong> The Panel will determine applications by majority, with written reasons to be prepared by the Chair (including any dissenting decision or a summary of any dissenting decision) and provided to the parties.</p><p><strong>j.</strong> A determination of the Panel will be considered binding unless either the Union or VHIA make an application to have the determination reviewed by the Commission within 14 days of receiving written determination.</p><p><strong>k.</strong> An application to the Commission will include the application, determination, written reasons and supporting material.</p><p><strong>l.</strong> An application under this clause will include a request that the President of the Commission appoint a member of the Commission to preside over the matter.</p><p><strong>m.</strong> The Commission will be assisted by the Panel Chair, who will explain Panel’s recommendation, the application and supporting material, and inform the Commission of the position of the Union and the VHIA.</p><p><strong>n.</strong> The Commission will adopt an inquisitorial procedure (rather than an adversarial procedure) and will in effect stand in the shoes of the Panel and determine whether the Panel decision under review was properly reached, and may substitute or uphold the existing determination. Any determination under this clause will be final and binding upon the parties and will not be subject to an appeal of the Full Bench.</p><p><strong>12.6</strong> Right of the Department to be heard The HSU and the VHIA recognise that the Victorian Government, represented by the Department of Health, has a right to have its funding interests heard and considered in decisions of the Panel.</p><p><strong>12.7</strong> Materials to be provided to the Panel</p><p><strong>a.</strong> A Party shall provide all relevant material to the Panel and the other Party as soon as practicable. Relevant material may include the following:</p><p><strong>(i)</strong> Staffing/EFT levels and profiles</p><p><strong>(ii)</strong> position descriptions</p><p><strong>(iii)</strong> rosters</p><p><strong>(iv)</strong> prioritised work arrangements made under <a href="/eba/ebas/mspp/workforce-management/34-planned-and-unplanned-absences.html">clause 34</a></p><p><strong>(v)</strong> proposed and/or actual professional reporting lines for/to the proposed position/s</p><p><strong>(vi)</strong> records relating to an application (for example: leave backfill, vacancies, absenteeism and leave accruals)</p><p><strong>(vii)</strong> organisational structure</p><p><strong>(viii)</strong> information referred to in <a href="/eba/ebas/mspp/union-rights/17-union-rights.html">clause 17.10</a> (WIC)</p><p><strong>12.8</strong> Notification of Panel determinations</p><p><strong>a.</strong> The Chair will notify the HSU, Employer and Employee, where applicable, of the Panel’s determination with respect to an application in writing within 14 days of the decision.</p><p><strong>b.</strong> In the case of an application for a reclassification the determined grade will apply from the date of the application or a later date determined by the Panel.</p><p><strong>c.</strong> Until the determination of the Panel, the existing grade (where relevant) will continue to apply.</p><p><strong>d.</strong> In the case of an application for a reclassification, where the Panel or, on review, the Commission determines that a lower classification applies, the Employee will have their current salary maintained.</p><p><strong>12.9</strong> Employee Release from normal duty</p><p><strong>a.</strong> An Employee who is involved in a dispute before the Panel, including an HSU representative, will be released by the Employer with pay from normal duties</p><p>as is reasonably necessary to enable them to participate in this dispute settling procedure so long as it does not unduly affect the operations of the Employer.</p><p><strong>b.</strong> For the purposes of this clause ‘pay’ shall include shift allowances and any other payment the employee or HSU representative would have received had they not been released from duty as described above.</p><p><strong>12.10</strong> Withdrawal of application</p><p><strong>a.</strong> The notifier of a dispute to the Panel may withdraw their application at any time.</p><p><strong>b.</strong> Any notice of withdrawal of a matter shall be in writing and the Chair shall cause this to be communicated to other relevant parties.</p><p>Plain language terms: IDRP, dispute panel.</p>',80)])])}const m=t(o,[["render",s]]);export{g as __pageData,m as default};
